        return 'yaml'
    return None

def parse_exchange_table_file(f):
    # Expect header: compound\tlower\tupper
    header = f.readline()
    for line in f:
        if line.startswith('#') or not line.strip():
            continue
        parts = line.strip().split('\t')
        if len(parts) != 3:
            continue
        compound, lower, upper = parts[0], parts[1], parts[2]
        if not compound.isalnum():
            continue
        lower, upper = float(lower), float(upper)
        if lower > upper:
            continue
        yield {'compound': compound, 'lower': lower, 'upper': upper}

def parse_exchange_yaml_file(context, f, default_compartment):
    # Minimal YAML-like stub: each line "compound:lower:upper[:compartment]"
    for line in f:
        if line.startswith('#') or not line.strip():
            continue
        parts = line.strip().split(':')
        if len(parts) < 3:
            continue
        compound = parts[0]
        if not compound.isalnum():
            continue
        lower, upper = float(parts[1]), float(parts[2])
        if lower > upper:
            continue
        entry = {
            'compound': compound,
            'lower': lower,
            'upper': upper,
            'compartment': parts[3] if len(parts) > 3 else default_compartment
        }
        yield entry

